public class TryWithResourcesDemo {
    public static void main(String[] args) {
        // try-with-resources with file
        try (FileWriter writer = new FileWriter("test.txt")) {
            writer.write("Hello, try-with-resources!");
            System.out.println("File written successfully");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // Multiple resources
        try (FileReader reader = new FileReader("test.txt");
             BufferedReader bufferedReader = new BufferedReader(reader)) {
            String line = bufferedReader.readLine();
            System.out.println("Read: " + line);
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }

        // Custom AutoCloseable resource
        try (MyResource resource = new MyResource()) {
            resource.use();
        } catch (Exception e) {
            System.out.println("Exception: " + e.getMessage());
        }

        // Scanner with try-with-resources
        try (Scanner scanner = new Scanner(System.in)) {
            System.out.print("Enter text: ");
            String input = scanner.nextLine();
            System.out.println("You entered: " + input);
        }
    }
}

class MyResource implements AutoCloseable {
    @Override
    public void close() throws Exception {
        System.out.println("Resource closed automatically");
    }

    void use() {
        System.out.println("Using resource");
    }
}

import java.io.*;

public class ThrowThrowsDemo {

    // Method using throws
    public static void validateAge(int age) throws IllegalArgumentException {
        if (age < 0 || age > 150) {
            // Using throw
            throw new IllegalArgumentException("Invalid age: " + age);
        }
        System.out.println("Valid age: " + age);
    }

    // Method throwing multiple exceptions
    public static void processFile(String filename) throws IOException, NumberFormatException {
        if (filename == null) {
            throw new NullPointerException("Filename is null");
        }

        // Simulate file processing
        System.out.println("Processing: " + filename);

        // Using throw for custom exception
        if (filename.equals("error.txt")) {
            throw new IOException("File not found: " + filename);
        }
    }

    public static void main(String[] args) {
        // Handling checked exception
        try {
            validateAge(25);
            validateAge(200);  // This will throw exception
        } catch (IllegalArgumentException e) {
            System.out.println("Caught: " + e.getMessage());
        }

        // Handling multiple exceptions
        try {
            processFile("data.txt");
            processFile("error.txt");  // This will throw IOException
        } catch (IOException e) {
            System.out.println("IOException caught: " + e.getMessage());
        } catch (NumberFormatException e) {
            System.out.println("NumberFormatException caught: " + e.getMessage());
        } catch (NullPointerException e) {
            System.out.println("NullPointerException caught: " + e.getMessage());
        }

        // Re-throwing exceptions
        try {
            processFile(null);
        } catch (Exception e) {
            // Re-throw as runtime exception
            throw new RuntimeException("Error processing: " + e.getMessage());
        }
    }
}

