class InsufficientBalanceException extends Exception {
    private double balance;
    private double attemptedWithdraw;

    public InsufficientBalanceException(String message, double balance, double amount) {
        super(message);
        this.balance = balance;
        this.attemptedWithdraw = amount;
    }

    public double getBalance() { return balance; }
    public double getAttemptedWithdraw() { return attemptedWithdraw; }
}

// Custom unchecked exception
class InvalidAccountException extends RuntimeException {
    public InvalidAccountException(String message) {
        super(message);
    }
}

class BankAccount {
    private String accountNumber;
    private double balance;

    BankAccount(String accountNumber, double balance) {
        this.accountNumber = accountNumber;
        this.balance = balance;
    }

    void withdraw(double amount) throws InsufficientBalanceException {
        if (amount <= 0) {
            throw new InvalidAccountException("Invalid withdrawal amount: " + amount);
        }
        if (amount > balance) {
            throw new InsufficientBalanceException(
                "Insufficient balance", balance, amount);
        }
        balance -= amount;
        System.out.println("Withdrawn: $" + amount + ", New balance: $" + balance);
    }

    void display() {
        System.out.println("Account: " + accountNumber + ", Balance: $" + balance);
    }
}

public class CustomExceptionDemo {
    public static void main(String[] args) {
        BankAccount account = new BankAccount("12345", 1000.0);

        System.out.println("Initial account:");
        account.display();

        try {
            account.withdraw(500);  // Successful
            account.withdraw(600);  // Insufficient balance
        } catch (InsufficientBalanceException e) {
            System.out.println("\nInsufficientBalanceException caught:");
            System.out.println("Message: " + e.getMessage());
            System.out.println("Balance: $" + e.getBalance());
            System.out.println("Attempted: $" + e.getAttemptedWithdraw());
        } catch (InvalidAccountException e) {
            System.out.println("InvalidAccountException: " + e.getMessage());
        }

        // Testing invalid amount
        try {
            account.withdraw(-100);
        } catch (InsufficientBalanceException e) {
            System.out.println("This won't happen");
        } catch (InvalidAccountException e) {
            System.out.println("\nInvalidAccountException: " + e.getMessage());
        }
    }
}

public class ExceptionChainingDemo {

    public static void method1() throws Exception {
        try {
            method2();
        } catch (NullPointerException e) {
            // Exception chaining using constructor
            throw new Exception("Error in method1", e);
        }
    }

    public static void method2() {
        try {
            method3();
        } catch (ArithmeticException e) {
            // Exception chaining using initCause
            RuntimeException re = new RuntimeException("Error in method2");
            re.initCause(e);
            throw re;
        }
    }

    public static void method3() {
        // Original exception
        int result = 10 / 0;  // ArithmeticException
    }

    public static void main(String[] args) {
        try {
            method1();
        } catch (Exception e) {
            System.out.println("Top-level exception: " + e.getMessage());
            System.out.println("Cause: " + e.getCause().getMessage());
            System.out.println("\nFull stack trace:");
            e.printStackTrace();
        }

        // Another example of chaining
        try {
            readFile();
        } catch (Exception e) {
            System.out.println("\n\nChained exception from file handling:");
            Throwable cause = e;
            while (cause != null) {
                System.out.println("-> " + cause.getClass().getSimpleName() + ": " + cause.getMessage());
                cause = cause.getCause();
            }
        }
    }

    static void readFile() throws Exception {
        try {
            // Simulate file error
            throw new java.io.IOException("File not found");
        } catch (java.io.IOException e) {
            throw new Exception("File processing failed", e);
        }
    }
}
